import{_ as i,c as e,o as a,ae as o}from"./chunks/framework.B7Y1jjX-.js";const r="/pressidian/assets/Pasted%20image%2020251206001911.Eg0XNZyU.png",p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/前端技术栈.md","filePath":"generated-notes/前端/前端技术栈.md"}'),t={name:"generated-notes/前端/前端技术栈.md"};function n(s,l,u,c,d,h){return a(),e("div",null,[...l[0]||(l[0]=[o('<p>掌握：</p><ul><li>HTML 会用</li><li>CS 会用</li><li>JS、es6 会用</li><li>Vue 会用，并且有一定的原理认识，有一个较为完善的小项目</li><li>ElementPlus 会用</li><li>tailwindcss 会用</li><li>sass 会用</li><li>fontawesome 会用</li><li>echart 会用</li><li>vite 会用，但是对于打包部分还是有些不太熟悉</li><li>git 会用</li><li>pinia 会用</li><li>vue router 会用，并且有一定的原理认识</li><li>gasp 会用</li><li>Bootstrap 会用 目标：</li><li>近期：Webpack与Vite打包、TS 、jest、node</li><li>中期：monorepo pnpm、react</li><li>后期：跨端、性能优化</li></ul><p><img src="'+r+'" alt="Pasted image 20251206001911.png"></p><h3 id="必须关注的方向" tabindex="-1">必须关注的方向： <a class="header-anchor" href="#必须关注的方向" aria-label="Permalink to &quot;必须关注的方向：&quot;">​</a></h3><ul><li><strong>TypeScript生态</strong></li><li><strong>构建工具演进</strong>（Vite、Turbopack）</li><li><strong>跨端开发</strong>（小程序、移动端）</li><li><strong>性能与用户体验</strong></li><li><strong>AI工程化</strong>（前端与AI结合） 你已经具备了很好的Vue技术栈基础，这是很大的优势。现在需要的是在<strong>类型安全</strong>、<strong>工程化深度</strong>和<strong>性能优化</strong>方面加强。</li></ul><p><strong>立即开始：</strong> TypeScript<br><strong>重点加强：</strong> Vite打包和构建优化<br><strong>选择性了解：</strong> Webpack原理<br> 从前端工程师的职业发展角度来看，<strong>TypeScript</strong> 和 <strong>Webpack</strong> 是必须掌握的技术，这两者在现代前端开发中占有重要地位。</p><p>针对 <strong>TypeScript (TS)</strong>、<strong>Vite</strong> 和 <strong>Webpack</strong> 的学习，建议按以下步骤进行，确保全面掌握每个工具的核心概念、应用场景和实践能力。下面是一份详细的学习计划：</p><hr><h3 id="学习计划-typescript-ts" tabindex="-1"><strong>学习计划：TypeScript (TS)</strong> <a class="header-anchor" href="#学习计划-typescript-ts" aria-label="Permalink to &quot;**学习计划：TypeScript (TS)**&quot;">​</a></h3><p><strong>目标</strong>：掌握 TypeScript 的基本语法、类型系统、进阶特性，能在 Vue 3 项目中使用 TS。</p><h4 id="_1-基础阶段-约-2-周" tabindex="-1">1. <strong>基础阶段</strong>（约 2 周） <a class="header-anchor" href="#_1-基础阶段-约-2-周" aria-label="Permalink to &quot;1. **基础阶段**（约 2 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：理解 TypeScript 的基本概念，熟悉其语法和类型系统。</li></ul><h5 id="学习内容" tabindex="-1">学习内容： <a class="header-anchor" href="#学习内容" aria-label="Permalink to &quot;学习内容：&quot;">​</a></h5><ul><li><strong>类型系统</strong>： <ul><li>基本类型：<code>string</code>、<code>number</code>、<code>boolean</code>、<code>null</code>、<code>undefined</code>、<code>any</code>、<code>unknown</code>、<code>void</code>、<code>never</code>。</li><li>类型推导与类型注解。</li><li>数组、元组、对象类型。</li></ul></li><li><strong>接口与类型别名</strong>： <ul><li><code>interface</code> 与 <code>type</code> 的区别与使用。</li><li>类和接口的结合，如何使用接口来约束类。</li></ul></li><li><strong>函数类型</strong>： <ul><li>函数声明与表达式的类型。</li><li>函数重载、可选参数和默认参数。</li></ul></li><li><strong>类与对象</strong>： <ul><li>类的基本语法：构造函数、继承、修饰符。</li><li>实现接口、抽象类。</li></ul></li><li><strong>联合类型与交叉类型</strong>： <ul><li>使用 <code>|</code> 和 <code>&amp;</code> 运算符来定义联合类型和交叉类型。</li></ul></li></ul><h5 id="学习资源" tabindex="-1">学习资源： <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源：&quot;">​</a></h5><ul><li><a href="https://www.typescriptlang.org/docs/" target="_blank" rel="noreferrer">TypeScript 官方文档</a></li><li><a href="https://ts.xcatliu.com/" target="_blank" rel="noreferrer">TypeScript 入门教程</a></li></ul><h5 id="实践" tabindex="-1">实践： <a class="header-anchor" href="#实践" aria-label="Permalink to &quot;实践：&quot;">​</a></h5><ul><li>将你目前的 Vue 项目中，逐步迁移到 TypeScript。 <ul><li>将 <code>.js</code> 文件转为 <code>.ts</code>。</li><li>加入类型注解和类型检查，解决潜在的类型问题。</li></ul></li></ul><hr><h4 id="_2-进阶阶段-约-3-周" tabindex="-1">2. <strong>进阶阶段</strong>（约 3 周） <a class="header-anchor" href="#_2-进阶阶段-约-3-周" aria-label="Permalink to &quot;2. **进阶阶段**（约 3 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：掌握 TS 的进阶特性，能够在更复杂的项目中应用。</li></ul><h5 id="学习内容-1" tabindex="-1">学习内容： <a class="header-anchor" href="#学习内容-1" aria-label="Permalink to &quot;学习内容：&quot;">​</a></h5><ul><li><strong>泛型</strong>： <ul><li>泛型函数、类、接口。</li><li>泛型约束：限制泛型的类型。</li><li>使用泛型增强代码的复用性。</li></ul></li><li><strong>模块与命名空间</strong>： <ul><li>导入导出：<code>import</code> 和 <code>export</code>。</li><li>使用 <code>default</code> 导出。</li><li>声明模块。</li></ul></li><li><strong>装饰器</strong>（如果你有兴趣或者需要在 Vue 中使用）： <ul><li>类装饰器、方法装饰器、属性装饰器。</li></ul></li><li><strong>高级类型</strong>： <ul><li>映射类型、条件类型、索引类型。</li><li><code>keyof</code>、<code>infer</code> 等运算符的使用。</li><li><code>Readonly</code>、<code>Partial</code> 等内置工具类型。</li></ul></li></ul><h5 id="学习资源-1" tabindex="-1">学习资源： <a class="header-anchor" href="#学习资源-1" aria-label="Permalink to &quot;学习资源：&quot;">​</a></h5><ul><li><a href="https://ts.xcatliu.com/" target="_blank" rel="noreferrer">TypeScript 深入浅出</a>（适合进阶学习）</li></ul><h5 id="实践-1" tabindex="-1">实践： <a class="header-anchor" href="#实践-1" aria-label="Permalink to &quot;实践：&quot;">​</a></h5><ul><li>使用 TypeScript 编写一个中型项目，例如一个带有 CRUD 操作的管理后台，增强项目的类型安全性。</li><li>在 Vue 3 项目中，完全使用 TS 重构，配合 Pinia 和 Vue Router 使用 TS。</li></ul><hr><h4 id="_3-项目应用阶段-约-2-周" tabindex="-1">3. <strong>项目应用阶段</strong>（约 2 周） <a class="header-anchor" href="#_3-项目应用阶段-约-2-周" aria-label="Permalink to &quot;3. **项目应用阶段**（约 2 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：将所学的 TS 知识在实际项目中运用，提升实践能力。</li></ul><h5 id="实践内容" tabindex="-1">实践内容： <a class="header-anchor" href="#实践内容" aria-label="Permalink to &quot;实践内容：&quot;">​</a></h5><ul><li>完成一个小型 <strong>Vue 3 + TypeScript + Pinia</strong> 的项目，使用 TypeScript 完整管理项目的状态、路由及视图层。</li><li>在项目中： <ul><li>使用泛型、接口、类型别名等类型系统特性。</li><li>配合 Vue 3 的 Composition API 使用 TS。</li><li>使用 <code>tsconfig.json</code> 配置文件来优化项目结构。</li></ul></li></ul><hr><h3 id="学习计划-vite" tabindex="-1"><strong>学习计划：Vite</strong> <a class="header-anchor" href="#学习计划-vite" aria-label="Permalink to &quot;**学习计划：Vite**&quot;">​</a></h3><p><strong>目标</strong>：熟悉 Vite 的基本概念，掌握如何配置、使用 Vite 进行开发和构建优化。</p><h4 id="_1-基础阶段-约-1-周" tabindex="-1">1. <strong>基础阶段</strong>（约 1 周） <a class="header-anchor" href="#_1-基础阶段-约-1-周" aria-label="Permalink to &quot;1. **基础阶段**（约 1 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：了解 Vite 的工作原理和基本配置。</li></ul><h5 id="学习内容-2" tabindex="-1">学习内容： <a class="header-anchor" href="#学习内容-2" aria-label="Permalink to &quot;学习内容：&quot;">​</a></h5><ul><li><strong>Vite 简介与工作原理</strong>： <ul><li>与 Webpack 比较，Vite 的启动速度和热更新优势。</li><li>Vite 的开发模式与生产模式的区别。</li></ul></li><li><strong>Vite 安装与基础配置</strong>： <ul><li>使用 Vite 创建项目：<code>npm create vite@latest</code>。</li><li><code>vite.config.js</code> 配置文件的结构与常见配置。</li><li>配置别名、插件、环境变量等。</li></ul></li></ul><h5 id="学习资源-2" tabindex="-1">学习资源： <a class="header-anchor" href="#学习资源-2" aria-label="Permalink to &quot;学习资源：&quot;">​</a></h5><ul><li><a href="https://vitejs.dev/" target="_blank" rel="noreferrer">Vite 官方文档</a></li></ul><h5 id="实践-2" tabindex="-1">实践： <a class="header-anchor" href="#实践-2" aria-label="Permalink to &quot;实践：&quot;">​</a></h5><ul><li>用 Vite 创建一个基础的 Vue 3 项目，熟悉其配置与开发流程。</li><li>尝试不同的 Vite 插件，如 Vue 插件、CSS 预处理插件等。</li></ul><hr><h4 id="_2-进阶阶段-约-2-周" tabindex="-1">2. <strong>进阶阶段</strong>（约 2 周） <a class="header-anchor" href="#_2-进阶阶段-约-2-周" aria-label="Permalink to &quot;2. **进阶阶段**（约 2 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：深入理解 Vite 的优化、构建流程，掌握高级配置。</li></ul><h5 id="学习内容-3" tabindex="-1">学习内容： <a class="header-anchor" href="#学习内容-3" aria-label="Permalink to &quot;学习内容：&quot;">​</a></h5><ul><li><strong>Vite 的构建与优化</strong>： <ul><li>如何优化项目的构建速度与性能：缓存、代码分割、懒加载等。</li><li>Vite 的生产模式：构建、压缩、Tree Shaking 等。</li></ul></li><li><strong>插件系统</strong>： <ul><li>编写自定义 Vite 插件。</li><li>使用官方插件，如 <code>@vitejs/plugin-vue</code>、<code>vite-plugin-svelte</code> 等。</li></ul></li><li><strong>HMR（Hot Module Replacement）</strong>： <ul><li>了解 Vite 的热更新机制，如何自定义热更新行为。</li></ul></li></ul><h5 id="学习资源-3" tabindex="-1">学习资源： <a class="header-anchor" href="#学习资源-3" aria-label="Permalink to &quot;学习资源：&quot;">​</a></h5><ul><li><a href="https://vitejs.dev/config/" target="_blank" rel="noreferrer">Vite 构建与优化</a></li></ul><h5 id="实践-3" tabindex="-1">实践： <a class="header-anchor" href="#实践-3" aria-label="Permalink to &quot;实践：&quot;">​</a></h5><ul><li>在 Vue 项目中使用 Vite 配置与优化： <ul><li>启用代码分割和懒加载，优化构建。</li><li>使用 Vite 插件处理样式、图片等静态资源。</li></ul></li></ul><hr><h3 id="学习计划-webpack" tabindex="-1"><strong>学习计划：Webpack</strong> <a class="header-anchor" href="#学习计划-webpack" aria-label="Permalink to &quot;**学习计划：Webpack**&quot;">​</a></h3><p><strong>目标</strong>：全面掌握 Webpack 的工作原理、配置、插件系统，能熟练使用 Webpack 进行复杂项目构建。</p><h4 id="_1-基础阶段-约-2-周-1" tabindex="-1">1. <strong>基础阶段</strong>（约 2 周） <a class="header-anchor" href="#_1-基础阶段-约-2-周-1" aria-label="Permalink to &quot;1. **基础阶段**（约 2 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：理解 Webpack 的核心概念，掌握基础配置和常见插件的使用。</li></ul><h5 id="学习内容-4" tabindex="-1">学习内容： <a class="header-anchor" href="#学习内容-4" aria-label="Permalink to &quot;学习内容：&quot;">​</a></h5><ul><li><strong>Webpack 简介与核心概念</strong>： <ul><li>打包、加载器（Loader）、插件（Plugin）的概念与作用。</li><li>Webpack 的构建流程：依赖图、模块化、打包过程。</li></ul></li><li><strong>Webpack 配置文件</strong>： <ul><li><code>webpack.config.js</code> 配置项详解（<code>entry</code>、<code>output</code>、<code>loaders</code>、<code>plugins</code>）。</li><li>配置常用的 Loader（如 <code>babel-loader</code>、<code>style-loader</code>、<code>css-loader</code>）。</li><li>配置常用的 Plugin（如 <code>HtmlWebpackPlugin</code>、<code>MiniCssExtractPlugin</code>）。</li></ul></li></ul><h5 id="学习资源-4" tabindex="-1">学习资源： <a class="header-anchor" href="#学习资源-4" aria-label="Permalink to &quot;学习资源：&quot;">​</a></h5><ul><li><a href="https://webpack.js.org/" target="_blank" rel="noreferrer">Webpack 官方文档</a></li></ul><h5 id="实践-4" tabindex="-1">实践： <a class="header-anchor" href="#实践-4" aria-label="Permalink to &quot;实践：&quot;">​</a></h5><ul><li>创建一个简单的 Webpack 项目，配置 <code>babel-loader</code> 来支持 ES6 转换，使用 <code>html-webpack-plugin</code> 插件自动生成 HTML。</li></ul><hr><h4 id="_2-进阶阶段-约-3-周-1" tabindex="-1">2. <strong>进阶阶段</strong>（约 3 周） <a class="header-anchor" href="#_2-进阶阶段-约-3-周-1" aria-label="Permalink to &quot;2. **进阶阶段**（约 3 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：深入理解 Webpack 的高级配置、性能优化、构建策略。</li></ul><h5 id="学习内容-5" tabindex="-1">学习内容： <a class="header-anchor" href="#学习内容-5" aria-label="Permalink to &quot;学习内容：&quot;">​</a></h5><ul><li><strong>优化与性能</strong>： <ul><li>代码拆分：<code>SplitChunksPlugin</code> 和 <code>Dynamic Import</code>。</li><li>缓存优化：<code>cache</code> 和 <code>contenthash</code>。</li><li>Tree Shaking：减少无用代码。</li></ul></li><li><strong>高级插件与加载器</strong>： <ul><li>使用 <code>eslint-loader</code>、<code>stylelint</code> 等开发时插件进行代码检查。</li><li>使用 <code>DefinePlugin</code>、<code>ProvidePlugin</code> 等进行构建时的变量注入。</li></ul></li><li><strong>使用 Webpack 和 Babel 集成进行转译</strong>： <ul><li>配置 Babel 来支持 ES6 以上语法和 JSX。</li></ul></li></ul><h5 id="学习资源-5" tabindex="-1">学习资源： <a class="header-anchor" href="#学习资源-5" aria-label="Permalink to &quot;学习资源：&quot;">​</a></h5><ul><li><a href="https://webpack.js.org/guides/build-performance/" target="_blank" rel="noreferrer">Webpack 性能优化指南</a></li></ul><h5 id="实践-5" tabindex="-1">实践： <a class="header-anchor" href="#实践-5" aria-label="Permalink to &quot;实践：&quot;">​</a></h5><ul><li>在 Vue 项目中使用 Webpack 进行配置，尝试代码分割、缓存优化等技术。</li><li>配置 Webpack 处理更复杂的资源，例如图像、字体、CSS 和 Sass。</li></ul><hr><h4 id="_3-项目应用阶段-约-2-周-1" tabindex="-1">3. <strong>项目应用阶段</strong>（约 2 周） <a class="header-anchor" href="#_3-项目应用阶段-约-2-周-1" aria-label="Permalink to &quot;3. **项目应用阶段**（约 2 周）&quot;">​</a></h4><ul><li><strong>核心目标</strong>：在实际项目中使用 Webpack，综合应用所学知识。</li></ul><h5 id="实践内容-1" tabindex="-1">实践内容： <a class="header-anchor" href="#实践内容-1" aria-label="Permalink to &quot;实践内容：&quot;">​</a></h5><ul><li>在一个大型的 Vue 3 项目中使用 Webpack 进行配置，结合 TS 和 Vue Router 使用 Webpack。</li><li>实现代码拆分、动态导入、按需加载等性能优化策略。</li><li>配置生产环境与开发环境的构建差异，掌握调试技巧。</li></ul><hr><p>我整理了「浏览器与环境」「业务复杂度」的学习清单，包含核心知识点+实践方向+工具，帮你分阶段突破：</p><h3 id="一、浏览器与环境-学习清单" tabindex="-1">一、浏览器与环境 学习清单 <a class="header-anchor" href="#一、浏览器与环境-学习清单" aria-label="Permalink to &quot;一、浏览器与环境 学习清单&quot;">​</a></h3><h4 id="一-基础阶段-核心原理" tabindex="-1">（一）基础阶段：核心原理 <a class="header-anchor" href="#一-基础阶段-核心原理" aria-label="Permalink to &quot;（一）基础阶段：核心原理&quot;">​</a></h4><ol><li><p><strong>浏览器底层机制</strong></p><ul><li>知识点： <ul><li>浏览器渲染流程（解析HTML→构建DOM→CSSOM→渲染树→布局→绘制）</li><li>重排（Reflow）/重绘（Repaint）的触发条件+优化方案</li><li>事件循环（宏任务/微任务）+异步渲染机制</li></ul></li><li>实践： <ul><li>用Chrome DevTools的「Performance」面板分析页面渲染耗时</li><li>写Demo验证“DOM操作顺序对重排的影响”</li></ul></li></ul></li><li><p><strong>跨域与安全</strong></p><ul><li>知识点： <ul><li>同源策略定义+跨域方案（CORS/JSONP/代理/PostMessage）</li><li>XSS/CSRF攻击原理+防御手段（CSP/Token）</li><li>浏览器存储（Cookie/LocalStorage/SessionStorage/IndexedDB）的区别+使用场景</li></ul></li><li>实践： <ul><li>搭建本地代理服务解决跨域</li><li>实现“防XSS的富文本输入框”</li></ul></li></ul></li><li><p><strong>环境适配</strong></p><ul><li>知识点： <ul><li>移动端适配：rem/vw/vh方案、viewport设置、Retina屏适配</li><li>多端兼容：PC端 vs 移动端浏览器差异、低版本浏览器（IE）兼容技巧</li><li>网络环境：弱网/断网适配（请求重试/缓存降级）</li></ul></li><li>实践： <ul><li>写一个自适应多端的页面（PC+移动端）</li><li>模拟弱网环境测试页面加载策略</li></ul></li></ul></li></ol><h4 id="二-进阶阶段-高级特性" tabindex="-1">（二）进阶阶段：高级特性 <a class="header-anchor" href="#二-进阶阶段-高级特性" aria-label="Permalink to &quot;（二）进阶阶段：高级特性&quot;">​</a></h4><ol><li><p><strong>缓存与性能</strong></p><ul><li>知识点： <ul><li>浏览器缓存：强缓存（Cache-Control/Expires）+协商缓存（ETag/Last-Modified）</li><li>HTTP缓存策略设计（如静态资源哈希命名）</li><li>预加载（preload）/预解析（preconnect）/懒加载（lazyload）</li></ul></li><li>实践： <ul><li>配置Nginx实现HTTP缓存策略</li><li>给图片/脚本加懒加载并测试加载性能</li></ul></li></ul></li><li><p><strong>高级环境技术</strong></p><ul><li>知识点： <ul><li>SSR（服务端渲染）/SSG（静态站点生成）原理+框架（Next.js/Nuxt.js）</li><li>PWA（渐进式Web应用）：Service Worker/缓存策略/离线可用</li><li>Web Worker：多线程任务（如大数据计算）</li></ul></li><li>实践： <ul><li>用Next.js写一个SSR页面</li><li>实现一个“离线可用的TodoList”（PWA）</li></ul></li></ul></li></ol><h3 id="二、业务复杂度-学习清单" tabindex="-1">二、业务复杂度 学习清单 <a class="header-anchor" href="#二、业务复杂度-学习清单" aria-label="Permalink to &quot;二、业务复杂度 学习清单&quot;">​</a></h3><h4 id="一-基础阶段-通用复杂场景" tabindex="-1">（一）基础阶段：通用复杂场景 <a class="header-anchor" href="#一-基础阶段-通用复杂场景" aria-label="Permalink to &quot;（一）基础阶段：通用复杂场景&quot;">​</a></h4><ol><li><p><strong>电商类场景</strong></p><ul><li>知识点： <ul><li>购物车：商品增删改查/选中状态同步/价格计算（防抖优化）</li><li>订单流程：多状态切换（待支付/已发货）/库存扣减（乐观锁/悲观锁）</li><li>支付：第三方支付对接（微信/支付宝）/支付状态轮询</li></ul></li><li>实践： <ul><li>实现“购物车商品数量变化时的实时价格计算”（处理并发修改）</li></ul></li></ul></li><li><p><strong>数据密集型场景</strong></p><ul><li>知识点： <ul><li>大数据表格：虚拟滚动（如vue-virtual-scroller）/列拖拽/单元格编辑</li><li>图表可视化：大数据量渲染（WebGL方案如ECharts GL）/实时数据更新</li></ul></li><li>实践： <ul><li>实现“10万条数据的虚拟滚动表格”</li></ul></li></ul></li></ol><h4 id="二-进阶阶段-高复杂度场景" tabindex="-1">（二）进阶阶段：高复杂度场景 <a class="header-anchor" href="#二-进阶阶段-高复杂度场景" aria-label="Permalink to &quot;（二）进阶阶段：高复杂度场景&quot;">​</a></h4><ol><li><p><strong>高并发/实时场景</strong></p><ul><li>知识点： <ul><li>直播/弹幕：WebSocket长连接/消息限流/弹幕防刷屏</li><li>实时协同：CRDT算法（多人编辑冲突解决）/WebSocket+心跳机制</li></ul></li><li>实践： <ul><li>用WebSocket实现“简易弹幕系统”（处理1000+用户并发发送）</li></ul></li></ul></li><li><p><strong>大型项目架构</strong></p><ul><li>知识点： <ul><li>状态管理：复杂状态拆分（如Redux分模块/ Zustand多Store）/状态持久化</li><li>权限系统：RBAC模型/动态路由/按钮级权限控制</li><li>微前端：qiankun/Module Federation（子应用通信/样式隔离）</li></ul></li><li>实践： <ul><li>实现“基于RBAC的权限管理系统”（动态生成菜单+按钮权限）</li></ul></li></ul></li></ol><h4 id="三-实战阶段-问题排查" tabindex="-1">（三）实战阶段：问题排查 <a class="header-anchor" href="#三-实战阶段-问题排查" aria-label="Permalink to &quot;（三）实战阶段：问题排查&quot;">​</a></h4><ul><li>知识点： <ul><li>线上问题定位：错误监控（Sentry）/用户行为埋点/日志分析</li><li>性能瓶颈：大文件上传（分片上传）/长列表卡顿（内存优化）</li></ul></li><li>实践： <ul><li>模拟“大文件分片上传+断点续传”功能</li></ul></li></ul><p>要不要我帮你补充一份<strong>每个知识点对应的学习资源（文档/教程）</strong>？</p>',92)])])}const b=i(t,[["render",n]]);export{p as __pageData,b as default};
